    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;
END;
DELIMITER ;
CREATE PROCEDURE SaveText()
BEGIN
    Call SaveTextAsFile('I hate humans');
END;
DELIMITER ;
CALL SaveText();
